#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define pii pair<int,int>
#define fr first
#define se second
#define pb push_back
using namespace std;
const int N = 2e4+5;
struct node{int l,r,h,p;}a[N];
int n,cnt,Mn,Mx,Lst,Answer;
struct SegTree{int sum,tag,len,pL,pR;}s[N*4];
int min(int x,int y){return (x<y?x:y);}
int max(int x,int y){return (x>y?x:y);}
int read(){
    int su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
bool cmp(node d1,node d2){
    return d1.h<d2.h||(d1.h==d2.h&&d1.p>d2.p);
}
int ls(int u){return (u<<1);}
int rs(int u){return (u<<1|1);}
void push_up(int u,int l,int r){
    if(s[u].tag){
        s[u].sum=1,s[u].len=r-l+1;
        s[u].pL=1,s[u].pR=1;return;
    }
    if(l==r){
        s[u].sum=0,s[u].len=0;
        s[u].pL=0,s[u].pR=0;return;
    }
    s[u].sum=s[ls(u)].sum+s[rs(u)].sum;
    if(s[ls(u)].pR&&s[rs(u)].pL)s[u].sum--;
    s[u].pL=s[ls(u)].pL,s[u].pR=s[rs(u)].pR;
    s[u].len=s[ls(u)].len+s[rs(u)].len;return;
}
void update(int u,int l,int r,int L,int R,LL k){
    if(L<=l&&r<=R){s[u].tag+=k;push_up(u,l,r);return;}
    int mid=(l+r)>>1;
    if(L<=mid)update(ls(u),l,mid,L,R,k);
    if(R>mid)update(rs(u),mid+1,r,L,R,k);
    push_up(u,l,r);return;
}
int main(){
    n=read(),Mn=0x3f3f3f3f;
    for(int i=1;i<=n;i++){
        int X1=read(),Y1=read();
        int X2=read(),Y2=read();
        Mn=min({Mn,X1,X2}),Mx=max({Mx,X1,X2});
        a[++cnt]={X1,X2,Y1,1},a[++cnt]={X1,X2,Y2,-1};
    }
    if(Mn<=0){
        for(int i=1;i<=cnt;i++)
            a[i].l+=-Mn+1,a[i].r+=-Mn+1;Mx-=Mn;
    }
    sort(a+1,a+cnt+1,cmp);
    for(int i=1;i<=cnt;i++){
        update(1,1,Mx,a[i].l,a[i].r-1,a[i].p);
        while(a[i+1].h==a[i].h&&a[i+1].p==a[i].p)
            ++i,update(1,1,Mx,a[i].l,a[i].r-1,a[i].p);
        Answer+=abs(s[1].len-Lst);
        Answer+=s[1].sum*2*(a[i+1].h-a[i].h),Lst=s[1].len;
    }
    cout<<Answer<<"\n";
    return 0;
}
